@using Microsoft.AspNetCore.Components.Forms

<div class="dropzone @(_isDragOver ? "dropzone-highlight" : "")"
     @ondragenter="HandleDragEnter"
     @ondragover="HandleDragOver"
     @ondragleave="HandleDragLeave"
     @ondrop="HandleDrop">
    <InputFile OnChange="HandleFileSelection" multiple class="dropzone-input" />
    <p class="dropzone-text">Drag &amp; drop files here, or click to browse</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _files)
        {
            <li class="file-entry @(entry.IsError ? "file-error" : "")">
                @if (entry.IsError)
                {
                    <span class="file-error-message">@entry.Name — exceeds 10 MB limit (@FormatSize(entry.Size))</span>
                }
                else
                {
                    <span class="file-name">@entry.Name</span>
                    <span class="file-size">@FormatSize(entry.Size)</span>
                    <span class="file-type">@entry.Type</span>
                }
                <button class="btn-remove" @onclick="() => RemoveFile(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSizeBytes = 10 * 1024 * 1024;

    private bool _isDragOver;
    private List<FileEntry> _files = new();

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private void HandleDragEnter() => _isDragOver = true;
    private void HandleDragOver() => _isDragOver = true;
    private void HandleDragLeave() => _isDragOver = false;

    private async Task HandleDrop()
    {
        _isDragOver = false;
        await Task.CompletedTask;
    }

    private async Task HandleFileSelection(InputFileChangeEventArgs e)
    {
        _isDragOver = false;

        foreach (var file in e.GetMultipleFiles(int.MaxValue))
        {
            var entry = new FileEntry(file.Name, file.Size, file.ContentType, file.Size > MaxFileSizeBytes);
            _files.Add(entry);
        }

        await NotifyParent();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files
            .Where(f => !f.IsError)
            .Select(f => new FileInfo(f.Name, f.Size, f.Type))
            .ToList();

        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    private record FileEntry(string Name, long Size, string Type, bool IsError);
}

.dropzone {
    position: relative;
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 160px;
    border: 2px dashed #6c757d;
    border-radius: 8px;
    background-color: #f8f9fa;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: pointer;
}

.dropzone-highlight {
    border-color: #0d6efd;
    background-color: #e7f1ff;
}

.dropzone-input {
    position: absolute;
    inset: 0;
    opacity: 0;
    cursor: pointer;
}

.dropzone-text {
    color: #6c757d;
    font-size: 1rem;
    pointer-events: none;
    margin: 0;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    align-items: center;
    gap: 1rem;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-entry.file-error {
    border-color: #dc3545;
    background-color: #fff5f5;
}

.file-error-message {
    color: #dc3545;
    flex: 1;
}

.file-name {
    font-weight: 500;
    flex: 1;
}

.file-size,
.file-type {
    color: #6c757d;
    font-size: 0.875rem;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.25rem 0.5rem;
    font-size: 0.8rem;
    cursor: pointer;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

