.dropzone {
    position: relative;
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 160px;
    border: 2px dashed #6c757d;
    border-radius: 8px;
    background-color: #f8f9fa;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: pointer;
}

.dropzone-highlight {
    border-color: #0d6efd;
    background-color: #e7f1ff;
}

.dropzone-input {
    position: absolute;
    inset: 0;
    opacity: 0;
    cursor: pointer;
}

.dropzone-text {
    color: #6c757d;
    font-size: 1rem;
    pointer-events: none;
    margin: 0;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    align-items: center;
    gap: 1rem;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-entry.file-error {
    border-color: #dc3545;
    background-color: #fff5f5;
}

.file-error-message {
    color: #dc3545;
    flex: 1;
}

.file-name {
    font-weight: 500;
    flex: 1;
}

.file-size,
.file-type {
    color: #6c757d;
    font-size: 0.875rem;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.25rem 0.5rem;
    font-size: 0.8rem;
    cursor: pointer;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

